from flask import Flask, redirect, url_for, session, request
import requests
import jwt
import os
import uuid

app = Flask(__name__)
app.secret_key = os.urandom(24)

# Configuration
OIDC_PROVIDER_URL = 'https://your-oidc-provider.com'
CLIENT_ID = 'your-client-id'
CLIENT_SECRET = 'your-client-secret'
REDIRECT_URI = 'http://localhost:5000/callback'
SCOPE = 'openid profile email'

@app.route('/')
def index():
    return 'Welcome to the OIDC Flask App! <a href="/login">Login</a>'

@app.route('/login')
def login():
    nonce = str(uuid.uuid4())
    session['nonce'] = nonce
    authorization_url = f"{OIDC_PROVIDER_URL}/authorize?response_type=code&client_id={CLIENT_ID}&redirect_uri={REDIRECT_URI}&scope={SCOPE}&nonce={nonce}"
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    code = request.args.get('code')
    nonce = session.pop('nonce', None)

    token_response = requests.post(f"{OIDC_PROVIDER_URL}/token", data={
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': REDIRECT_URI,
        'client_id': CLIENT_ID,
        'client_secret': CLIENT_SECRET
    })

    tokens = token_response.json()
    id_token = tokens.get('id_token')

    if id_token:
        decoded_token = jwt.decode(id_token, options={"verify_signature": False})
        if decoded_token.get('nonce') == nonce:
            session['user'] = decoded_token
            return f"Hello, {decoded_token['name']}! <a href='/logout'>Logout</a>"
    
    return 'Authentication failed', 401

@app.route('/logout')
def logout():
    session.pop('user', None)
    return redirect(url_for('index'))

if __name__ == '__main__':
    app.run(debug=True)